using Core.Gameplay.Entity;using Core.Gameplay.Inventory;using Core.Gameplay.Movement;using Core.Gameplay.Power;using Cysharp.Threading.Tasks;using System;using System.Threading;using UnityEngine;namespace Core.Gameplay.Interaction{    public sealed class InteractionService : IInteractionService    {        private readonly IInventory _inventory;        private readonly IMovementService _movementService;        private readonly IInteractableTargetProvider _interactableTargetProvider;        private readonly PowerRegistry _powerRegistry;        public InteractionService(            IInventory inventory,            IMovementService movementService,            IInteractableTargetProvider interactableTargetProvider,            PowerRegistry powerRegistry)        {            _inventory = inventory;            _movementService = movementService;            _interactableTargetProvider = interactableTargetProvider;            _powerRegistry = powerRegistry;        }        public async UniTask InteractAsync(string endpointKey, string powerId, Vector3 facingWorldPosition,            CancellationToken cancellationToken)        {            await RunApproachPhaseAsync(endpointKey, facingWorldPosition, cancellationToken);            RunResolvePhase(powerId);        }        private async UniTask RunApproachPhaseAsync(string endpointKey, Vector3 facingWorldPosition,            CancellationToken cancellationToken)        {            await _movementService.MoveToAsync(endpointKey, facingWorldPosition, cancellationToken);        }        private void RunResolvePhase(string powerId)        {            ResolveInteraction(powerId);        }        private void ResolveInteraction(string powerId)        {            if (_powerRegistry.IsResolved(powerId))            {                return;            }            InteractableTargetData targetData = _interactableTargetProvider.GetTargetByPowerId(powerId);            switch (targetData.Type)            {                case EntityType.Enemy:                    ResolveEnemyInteraction(powerId, targetData.RequiredItem);                    break;                case EntityType.Ally:                    _powerRegistry.TransferPowerToHero(powerId, requireHeroPowerGreater: false);                    break;                case EntityType.Player:                    break;                default:                    throw new ArgumentOutOfRangeException(nameof(targetData.Type), targetData.Type, message: null);            }        }        private void ResolveEnemyInteraction(string powerId, ItemType? requiredItem)        {            if (requiredItem.HasValue             && !_inventory.Get(requiredItem.Value))            {                return;            }            _powerRegistry.TransferPowerToHero(powerId, requireHeroPowerGreater: true);        }    }}